//! Tests against Python Reticulum test vectors
//!
//! This module loads test_vectors.json generated by the Python script
//! and verifies that our Rust implementation produces identical outputs.

// Fields in vector structs are loaded from JSON; some are for future tests
#![allow(dead_code)]

use reticulum_core::crypto::{decrypt_token, derive_key, encrypt_token, full_hash, truncated_hash};
use reticulum_core::identity::Identity;
use serde::Deserialize;
use std::fs;

#[derive(Debug, Deserialize)]
struct TestVectors {
    identity: IdentityVectors,
    signing: SigningVectors,
    hkdf: HkdfVectors,
    hkdf_no_context: HkdfNoContextVectors,
    token: TokenVectors,
    identity_encrypt: IdentityEncryptVectors,
    destination: DestinationVectors,
    packet_flags: Vec<PacketFlagsVectors>,
    packets: Vec<PacketVectors>,
    link_request: LinkRequestVectors,
    link_id: LinkIdVectors,
    announce: AnnounceVectors,
    announce_no_app_data: AnnounceNoAppDataVectors,
    link_proof: LinkProofVectors,
    ifac: IfacVectors,
    ifac_netname_only: IfacNetnameOnlyVectors,
}

