fn load_vectors() -> TestVectors {
    let path = concat!(
        env!("CARGO_MANIFEST_DIR"),
        "/../tests/vectors/test_vectors.json"
    );
    let content = fs::read_to_string(path).expect("Failed to read test vectors");
    serde_json::from_str(&content).expect("Failed to parse test vectors")
}

#[test]
fn test_identity_from_private_key() {
    let vectors = load_vectors();

    let private_key = hex::decode(&vectors.identity.private_key).unwrap();
    let expected_public = hex::decode(&vectors.identity.public_key).unwrap();
    let expected_hash = hex::decode(&vectors.identity.hash).unwrap();

    let identity = Identity::from_private_key_bytes(&private_key).unwrap();

    assert_eq!(
        identity.public_key_bytes().to_vec(),
        expected_public,
        "Public key mismatch"
    );
    assert_eq!(
        identity.hash().to_vec(),
        expected_hash,
        "Identity hash mismatch"
    );
}

#[test]
fn test_identity_signing() {
    let vectors = load_vectors();

    let private_key = hex::decode(&vectors.identity.private_key).unwrap();
    let message = hex::decode(&vectors.signing.message).unwrap();
    let expected_signature = hex::decode(&vectors.signing.signature).unwrap();

    let identity = Identity::from_private_key_bytes(&private_key).unwrap();
    let signature = identity.sign(&message).unwrap();

    assert_eq!(signature.to_vec(), expected_signature, "Signature mismatch");

    // Verify signature works
    assert!(identity.verify(&message, &signature).unwrap());
}

#[test]
fn test_hkdf_with_context() {
    let vectors = load_vectors();

    let ikm = hex::decode(&vectors.hkdf.ikm).unwrap();
    let salt = hex::decode(&vectors.hkdf.salt).unwrap();
    let info = hex::decode(&vectors.hkdf.info).unwrap();
    let expected = hex::decode(&vectors.hkdf.output).unwrap();

    let mut output = vec![0u8; vectors.hkdf.length];
    derive_key(&ikm, Some(&salt), Some(&info), &mut output);

    assert_eq!(output, expected, "HKDF with context output mismatch");
}

#[test]
fn test_hkdf_no_context() {
    let vectors = load_vectors();

    let ikm = hex::decode(&vectors.hkdf_no_context.ikm).unwrap();
    let salt = hex::decode(&vectors.hkdf_no_context.salt).unwrap();
    let expected = hex::decode(&vectors.hkdf_no_context.output).unwrap();

    let mut output = vec![0u8; vectors.hkdf_no_context.length];
    derive_key(&ikm, Some(&salt), None, &mut output);

    assert_eq!(output, expected, "HKDF without context output mismatch");
}

#[test]
fn test_token_encryption() {
    let vectors = load_vectors();

    let key = hex::decode(&vectors.token.key).unwrap();
    let iv = hex::decode(&vectors.token.iv).unwrap();
    let plaintext = hex::decode(&vectors.token.plaintext).unwrap();
    let expected_token = hex::decode(&vectors.token.token).unwrap();

    // Calculate buffer size: IV (16) + padded ciphertext + HMAC (32)
    let padded_len = ((plaintext.len() / 16) + 1) * 16;
    let mut token = vec![0u8; 16 + padded_len + 32];

    let iv_arr: [u8; 16] = iv.try_into().unwrap();
    let token_len = encrypt_token(&key, &iv_arr, &plaintext, &mut token).unwrap();
    token.truncate(token_len);

    assert_eq!(token, expected_token, "Token encryption mismatch");
}

#[test]
fn test_token_decryption() {
    let vectors = load_vectors();

    let key = hex::decode(&vectors.token.key).unwrap();
    let token = hex::decode(&vectors.token.token).unwrap();
    let expected_plaintext = hex::decode(&vectors.token.plaintext).unwrap();

    let mut plaintext = vec![0u8; token.len()];
    let plaintext_len = decrypt_token(&key, &token, &mut plaintext).unwrap();
    plaintext.truncate(plaintext_len);

    assert_eq!(plaintext, expected_plaintext, "Token decryption mismatch");
}

#[test]
fn test_identity_encrypt_deterministic() {
    let vectors = load_vectors();

    let private_key = hex::decode(&vectors.identity.private_key).unwrap();
    let ephemeral_private = hex::decode(&vectors.identity_encrypt.ephemeral_private_key).unwrap();
    let iv = hex::decode(&vectors.identity_encrypt.iv).unwrap();
    let plaintext = hex::decode(&vectors.identity_encrypt.plaintext).unwrap();
    let expected_ciphertext = hex::decode(&vectors.identity_encrypt.full_ciphertext).unwrap();

    let identity = Identity::from_private_key_bytes(&private_key).unwrap();

    let ephemeral_arr: [u8; 32] = ephemeral_private.try_into().unwrap();
    let iv_arr: [u8; 16] = iv.try_into().unwrap();

    let ciphertext = identity
        .encrypt_with_keys(&plaintext, &ephemeral_arr, &iv_arr)
        .unwrap();

    assert_eq!(
        hex::encode(&ciphertext),
        hex::encode(&expected_ciphertext),
        "Identity encrypt mismatch\nExpected: {}\nGot:      {}",
        hex::encode(&expected_ciphertext),
        hex::encode(&ciphertext)
    );
}

#[test]
fn test_identity_decrypt() {
    let vectors = load_vectors();

    let private_key = hex::decode(&vectors.identity.private_key).unwrap();
    let ciphertext = hex::decode(&vectors.identity_encrypt.full_ciphertext).unwrap();
    let expected_plaintext = hex::decode(&vectors.identity_encrypt.plaintext).unwrap();

    let identity = Identity::from_private_key_bytes(&private_key).unwrap();
    let decrypted = identity.decrypt(&ciphertext).unwrap();

    assert_eq!(decrypted, expected_plaintext, "Identity decrypt mismatch");
}

#[test]
fn test_destination_hash() {
    let vectors = load_vectors();

    let full_name = &vectors.destination.full_name;
    let expected_name_hash = hex::decode(&vectors.destination.name_hash).unwrap();
    let identity_hash = hex::decode(&vectors.destination.identity_hash).unwrap();
    let expected_dest_hash = hex::decode(&vectors.destination.destination_hash).unwrap();

    // Name hash is first 10 bytes of full_hash
    let name_hash_full = full_hash(full_name.as_bytes());
    let name_hash = &name_hash_full[..10];

    assert_eq!(name_hash.to_vec(), expected_name_hash, "Name hash mismatch");

    // Destination hash = truncated_hash(name_hash + identity_hash)
    let mut hash_material = Vec::with_capacity(10 + 16);
    hash_material.extend_from_slice(name_hash);
    hash_material.extend_from_slice(&identity_hash);

    let dest_hash = truncated_hash(&hash_material);

    assert_eq!(
        dest_hash.to_vec(),
        expected_dest_hash,
        "Destination hash mismatch"
    );
}

#[test]
fn test_encrypt_decrypt_roundtrip() {
    use rand_core::OsRng;

    // Test that our own encrypt/decrypt roundtrips correctly
    let identity = Identity::generate(&mut OsRng);
    let plaintext = b"Hello, this is a test message for roundtrip encryption!";

    let ciphertext = identity.encrypt(plaintext, &mut OsRng).unwrap();
    let decrypted = identity.decrypt(&ciphertext).unwrap();

    assert_eq!(decrypted, plaintext);
}

