#[test]
fn test_announce_signature_verification() {
    let vectors = load_all_vectors();
    let private_key = hex::decode(&vectors.identity.private_key).unwrap();

    // Create identity from private key
    let identity = Identity::from_private_key_bytes(&private_key).unwrap();

    // Verify announce structure
    let public_key = hex::decode(&vectors.announce.public_key).unwrap();
    let signature = hex::decode(&vectors.announce.signature).unwrap();
    let signed_data = hex::decode(&vectors.announce.signed_data).unwrap();

    // Verify that the public key from announce matches identity
    assert_eq!(
        identity.public_key_bytes().to_vec(),
        public_key,
        "Public key mismatch"
    );

    // Verify signature using identity
    assert!(
        identity.verify(&signed_data, &signature).unwrap(),
        "Announce signature verification failed"
    );
}

#[test]
fn test_announce_destination_hash() {
    let vectors = load_all_vectors();

    // Calculate destination hash from name_hash and identity_hash
    let name_hash = hex::decode(&vectors.announce.name_hash).unwrap();
    let identity_hash = hex::decode(&vectors.announce.identity_hash).unwrap();
    let expected_dest_hash = hex::decode(&vectors.announce.destination_hash).unwrap();

    // dest_hash = truncated_hash(name_hash + identity_hash)
    let mut hash_material = Vec::new();
    hash_material.extend_from_slice(&name_hash);
    hash_material.extend_from_slice(&identity_hash);

    let dest_hash = truncated_hash(&hash_material);

    assert_eq!(
        dest_hash.to_vec(),
        expected_dest_hash,
        "Announce destination hash mismatch"
    );
}

#[test]
fn test_announce_name_hash() {
    let vectors = load_all_vectors();

    // name_hash = first 10 bytes of full_hash(full_name)
    let full_name = &vectors.announce.full_name;
    let expected_name_hash = hex::decode(&vectors.announce.name_hash).unwrap();

    let name_hash_full = full_hash(full_name.as_bytes());
    let name_hash = &name_hash_full[..10];

    assert_eq!(
        name_hash.to_vec(),
        expected_name_hash,
        "Announce name hash mismatch"
    );
}

#[test]
fn test_announce_payload_parsing() {
    let vectors = load_all_vectors();

    // Parse announce payload
    let payload = hex::decode(&vectors.announce.payload).unwrap();
    let expected_public_key = hex::decode(&vectors.announce.public_key).unwrap();
    let expected_name_hash = hex::decode(&vectors.announce.name_hash).unwrap();
    let expected_random_hash = hex::decode(&vectors.announce.random_hash).unwrap();
    let expected_signature = hex::decode(&vectors.announce.signature).unwrap();
    let expected_app_data = hex::decode(&vectors.announce.app_data).unwrap();

    // Payload format: public_key(64) + name_hash(10) + random_hash(10) + signature(64) + app_data
    assert!(payload.len() >= 148, "Announce payload too short");

    let public_key = &payload[0..64];
    let name_hash = &payload[64..74];
    let random_hash = &payload[74..84];
    let signature = &payload[84..148];
    let app_data = &payload[148..];

    assert_eq!(public_key, &expected_public_key[..], "Public key mismatch");
    assert_eq!(name_hash, &expected_name_hash[..], "Name hash mismatch");
    assert_eq!(
        random_hash,
        &expected_random_hash[..],
        "Random hash mismatch"
    );
    assert_eq!(signature, &expected_signature[..], "Signature mismatch");
    assert_eq!(app_data, &expected_app_data[..], "App data mismatch");
}

#[test]
fn test_announce_no_app_data() {
    let vectors = load_all_vectors();
    let private_key = hex::decode(&vectors.identity.private_key).unwrap();

    let identity = Identity::from_private_key_bytes(&private_key).unwrap();

    let signed_data = hex::decode(&vectors.announce_no_app_data.signed_data).unwrap();
    let signature = hex::decode(&vectors.announce_no_app_data.signature).unwrap();

    // Verify signature
    assert!(
        identity.verify(&signed_data, &signature).unwrap(),
        "Announce (no app_data) signature verification failed"
    );

    // Verify payload is exactly 148 bytes (no app_data)
    let payload = hex::decode(&vectors.announce_no_app_data.payload).unwrap();
    assert_eq!(
        payload.len(),
        148,
        "Announce without app_data should be exactly 148 bytes"
    );
}

