#[test]
fn test_link_proof_signature() {
    let vectors = load_all_vectors();
    let private_key = hex::decode(&vectors.identity.private_key).unwrap();

    // The responder uses the destination's identity to sign
    let identity = Identity::from_private_key_bytes(&private_key).unwrap();

    let signed_data = hex::decode(&vectors.link_proof.signed_data).unwrap();
    let signature = hex::decode(&vectors.link_proof.signature).unwrap();

    // Verify signature
    assert!(
        identity.verify(&signed_data, &signature).unwrap(),
        "Link proof signature verification failed"
    );
}

#[test]
fn test_link_proof_payload_structure() {
    let vectors = load_all_vectors();

    let proof_payload = hex::decode(&vectors.link_proof.proof_payload).unwrap();
    let expected_signature = hex::decode(&vectors.link_proof.signature).unwrap();
    let expected_responder_pub = hex::decode(&vectors.link_proof.responder_x25519_public).unwrap();
    let expected_signalling = hex::decode(&vectors.link_proof.signalling_bytes).unwrap();

    // Proof format: signature(64) + responder_X25519_pub(32) + signalling(3) = 99 bytes
    assert_eq!(proof_payload.len(), 99, "Link proof should be 99 bytes");

    let signature = &proof_payload[0..64];
    let responder_pub = &proof_payload[64..96];
    let signalling = &proof_payload[96..99];

    assert_eq!(signature, &expected_signature[..], "Signature mismatch");
    assert_eq!(
        responder_pub,
        &expected_responder_pub[..],
        "Responder public key mismatch"
    );
    assert_eq!(
        signalling,
        &expected_signalling[..],
        "Signalling bytes mismatch"
    );
}

#[test]
fn test_link_proof_signed_data_structure() {
    let vectors = load_all_vectors();

    let signed_data = hex::decode(&vectors.link_proof.signed_data).unwrap();
    let link_id = hex::decode(&vectors.link_proof.link_id).unwrap();
    let initiator_x25519_pub = hex::decode(&vectors.link_proof.initiator_x25519_public).unwrap();
    let initiator_ed25519_pub = hex::decode(&vectors.link_proof.initiator_ed25519_public).unwrap();
    let signalling = hex::decode(&vectors.link_proof.signalling_bytes).unwrap();

    // Signed data: link_id(16) + initiator_X25519_pub(32) + initiator_Ed25519_pub(32) + signalling(3) = 83 bytes
    assert_eq!(signed_data.len(), 83, "Signed data should be 83 bytes");

    assert_eq!(
        &signed_data[0..16],
        &link_id[..],
        "Link ID mismatch in signed data"
    );
    assert_eq!(
        &signed_data[16..48],
        &initiator_x25519_pub[..],
        "Initiator X25519 pub mismatch"
    );
    assert_eq!(
        &signed_data[48..80],
        &initiator_ed25519_pub[..],
        "Initiator Ed25519 pub mismatch"
    );
    assert_eq!(
        &signed_data[80..83],
        &signalling[..],
        "Signalling mismatch in signed data"
    );
}

#[test]
fn test_link_key_derivation() {
    let vectors = load_all_vectors();

    let link_id = hex::decode(&vectors.link_proof.link_id).unwrap();
    let shared_key = hex::decode(&vectors.link_proof.shared_key).unwrap();
    let expected_derived = hex::decode(&vectors.link_proof.derived_key).unwrap();

    // Derive key using HKDF(shared_key, salt=link_id, context=None, length=64)
    let mut derived_key = [0u8; 64];
    derive_key(&shared_key, Some(&link_id), None, &mut derived_key);

    assert_eq!(
        derived_key.to_vec(),
        expected_derived,
        "Link key derivation mismatch"
    );
}

#[test]
fn test_link_ecdh_shared_key() {
    let vectors = load_all_vectors();

    let initiator_prv = hex::decode(&vectors.link_proof.initiator_x25519_private).unwrap();
    let responder_pub = hex::decode(&vectors.link_proof.responder_x25519_public).unwrap();
    let expected_shared = hex::decode(&vectors.link_proof.shared_key).unwrap();

    // Perform ECDH: initiator_private * responder_public
    let initiator_secret =
        x25519_dalek::StaticSecret::from(<[u8; 32]>::try_from(&initiator_prv[..]).unwrap());
    let responder_public =
        x25519_dalek::PublicKey::from(<[u8; 32]>::try_from(&responder_pub[..]).unwrap());

    let shared = initiator_secret.diffie_hellman(&responder_public);

    assert_eq!(
        shared.as_bytes().to_vec(),
        expected_shared,
        "ECDH shared key mismatch"
    );
}

#[test]
fn test_link_ecdh_symmetry() {
    let vectors = load_all_vectors();

    let initiator_prv = hex::decode(&vectors.link_proof.initiator_x25519_private).unwrap();
    let initiator_pub = hex::decode(&vectors.link_proof.initiator_x25519_public).unwrap();
    let responder_prv = hex::decode(&vectors.link_proof.responder_x25519_private).unwrap();
    let responder_pub = hex::decode(&vectors.link_proof.responder_x25519_public).unwrap();

    // Both sides should compute the same shared key
    let initiator_secret =
        x25519_dalek::StaticSecret::from(<[u8; 32]>::try_from(&initiator_prv[..]).unwrap());
    let responder_secret =
        x25519_dalek::StaticSecret::from(<[u8; 32]>::try_from(&responder_prv[..]).unwrap());
    let initiator_public =
        x25519_dalek::PublicKey::from(<[u8; 32]>::try_from(&initiator_pub[..]).unwrap());
    let responder_public =
        x25519_dalek::PublicKey::from(<[u8; 32]>::try_from(&responder_pub[..]).unwrap());

    let shared_from_initiator = initiator_secret.diffie_hellman(&responder_public);
    let shared_from_responder = responder_secret.diffie_hellman(&initiator_public);

    assert_eq!(
        shared_from_initiator.as_bytes(),
        shared_from_responder.as_bytes(),
        "ECDH should be symmetric"
    );
}

